#include <bits/stdc++.h>
using namespace std;

int n, m;

int u[100010];
int v[100010];
int cnt[1000010];

int main(){
	cin >> n >> m;
	for (int i = 1; i <= m; i++){
		cin >> u[i] >> v[i];
		cnt[u[i]]++;
		cnt[v[i]]++;
	}
	long long ans = 0;
	for (int i = 1; i <= m; i++){
		cnt[u[i]]--;
		cnt[v[i]]--;
		ans += cnt[u[i]] + cnt[v[i]];
	}
	cout << ans;
	return 0;
}
